{# =========================================================================
   SUMMARY PAGE — BP VARIANT (grouped by scope_group)
========================================================================= #}

{% set scopes = frappe.db.sql("""
    SELECT name, scope_name, scope_group, is_optional, direct_cost, quantity, uom,
           total_labor_cost, total_equipment_cost, total_material_cost
    FROM `tabEstimate Scope`
    WHERE estimate = %s
    ORDER BY scope_group ASC, COALESCE(display_order, 999) ASC, name ASC
""", doc.name, as_dict=True) %}

{% set base_scopes = scopes | selectattr("is_optional", "eq", 0) | list %}
{% set optional_scopes = scopes | selectattr("is_optional", "ne", 0) | list %}
{% set wbs = build_scope_wbs(base_scopes, optional_scopes) %}

{# BP parameters #}
{% set bp_rate = doc.bp_rate_factor | float or 1.0 %}
{% set bp_ocm_pct = doc.bp_ocm_percent | float %}
{% set bp_profit_pct = doc.bp_profit_percent | float %}

{# Compute total BP direct cost across all scopes #}
{% set bp_totals = namespace(base_dc=0, optional_dc=0) %}

{% for scope in scopes %}
  {% set mat_rows = frappe.db.sql("SELECT amount FROM `tabEstimate Scope Material` WHERE parent = %s", scope.name, as_dict=True) %}
  {% set bp_mat = namespace(value=0) %}
  {% for row in mat_rows %}{% set bp_mat.value = bp_mat.value + (row.amount | float) * bp_rate %}{% endfor %}
  {% set scope_bp_dc = (scope.total_labor_cost | float) + (scope.total_equipment_cost | float) + bp_mat.value %}
  {% if scope.is_optional %}
    {% set bp_totals.optional_dc = bp_totals.optional_dc + scope_bp_dc %}
  {% else %}
    {% set bp_totals.base_dc = bp_totals.base_dc + scope_bp_dc %}
  {% endif %}
{% endfor %}

{% set bp_all_dc = bp_totals.base_dc + bp_totals.optional_dc %}

<div style="page-break-after: always;">

  {{ cont_header() }}

  <div style="background-color: #1B2E4A; color: #ffffff; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 13pt; font-weight: 700; padding: 5px 10px; letter-spacing: 1px; margin-bottom: 8mm;">
    SUMMARY OF COST ESTIMATE
  </div>

  {% if scopes %}
  <table class="summary-table" style="table-layout: fixed; width: 100%; border-collapse: collapse; font-size: 9pt;">
    <colgroup>
      <col style="width: 45%;">
      <col style="width: 12%;">
      <col style="width: 13%;">
      <col style="width: 30%;">
    </colgroup>
    <thead>
      <tr>
        <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: left;">Scope of Work</th>
        <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: left;">UOM</th>
        <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: right;">Qty</th>
        <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: right;">Direct Cost</th>
      </tr>
    </thead>
    <tbody>

      {# Base scopes — grouped by scope_group #}
      {% set current_grp = namespace(value=None) %}
      {% set grp_idx = namespace(value=0) %}
      {% for scope in base_scopes %}
        {% if scope.scope_group != current_grp.value %}
          {% set current_grp.value = scope.scope_group %}
          {% set grp_idx.value = 0 %}
          <tr>
            <td colspan="4" style="background-color: #1B2E4A; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 2px 6px; font-size: 9pt; letter-spacing: 0.5px;">
              {{ wbs._group_numerals[scope.scope_group] }}. {{ scope.scope_group }}
            </td>
          </tr>
        {% endif %}
        {% set grp_idx.value = grp_idx.value + 1 %}
        <tr{% if grp_idx.value % 2 == 0 %} style="background-color: #F4F6F9;"{% endif %}>
          <td style="padding: 3px 6px 3px 12px; border-bottom: 1px solid #e8e8e8;">{{ wbs[scope.name].scope_num }} {{ scope.scope_name }}</td>
          <td style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ scope.uom if scope.uom and scope.uom != "None" else "&mdash;" }}</td>
          <td class="amount-cell" style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ num_format(scope.quantity) if (scope.quantity | float) > 0 else "" }}</td>
          <td class="amount-cell" style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope.direct_cost) }}</td>
        </tr>
      {% endfor %}

      {% if base_scopes %}
      <tr>
        <td colspan="3" style="text-align: right; font-weight: bold; padding: 3px 6px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">Base Scope Subtotal</td>
        <td class="amount-cell" style="font-weight: bold; padding: 3px 6px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">{{ php_format(doc.base_direct_cost) }}</td>
      </tr>
      {% endif %}

      {# Optional scopes — grouped #}
      {% if optional_scopes %}
      <tr>
        <td colspan="4" style="padding: 8px 8px 2px 8px; font-weight: bold; color: #2E5FA3; font-size: 8.5pt; font-style: italic;">
          Optional Scopes
        </td>
      </tr>
      {% set current_grp_opt = namespace(value=None) %}
      {% set grp_idx_opt = namespace(value=0) %}
      {% for scope in optional_scopes %}
        {% if scope.scope_group != current_grp_opt.value %}
          {% set current_grp_opt.value = scope.scope_group %}
          {% set grp_idx_opt.value = 0 %}
          <tr>
            <td colspan="4" style="background-color: #2E5FA3; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 4px 10px; font-size: 8.5pt; letter-spacing: 0.5px;">
              {{ wbs._group_numerals[scope.scope_group] }}. {{ scope.scope_group }}
            </td>
          </tr>
        {% endif %}
        {% set grp_idx_opt.value = grp_idx_opt.value + 1 %}
        <tr{% if grp_idx_opt.value % 2 == 0 %} style="background-color: #F4F6F9;"{% endif %}>
          <td style="padding: 3px 6px 3px 12px; border-bottom: 1px solid #e8e8e8;">{{ wbs[scope.name].scope_num }} {{ scope.scope_name }}</td>
          <td style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ scope.uom if scope.uom and scope.uom != "None" else "&mdash;" }}</td>
          <td class="amount-cell" style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ num_format(scope.quantity) if (scope.quantity | float) > 0 else "" }}</td>
          <td class="amount-cell" style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope.direct_cost) }}</td>
        </tr>
      {% endfor %}

      {% set optional_dc = namespace(total=0) %}
      {% for s in optional_scopes %}{% set optional_dc.total = optional_dc.total + (s.direct_cost | float) %}{% endfor %}
      <tr>
        <td colspan="3" style="text-align: right; font-weight: bold; padding: 3px 6px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">Optional Scope Subtotal</td>
        <td class="amount-cell" style="font-weight: bold; padding: 3px 6px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">{{ php_format(optional_dc.total) }}</td>
      </tr>
      {% endif %}

      {# Grand Total #}
      <tr>
        <td colspan="3" style="padding: 4px 6px; text-align: right; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-weight: bold; background-color: #1B2E4A; color: #ffffff;">Grand Total Direct Cost (All Scopes)</td>
        <td class="amount-cell" style="padding: 4px 6px; font-weight: bold; background-color: #1B2E4A; color: #ffffff;">{{ php_format(doc.direct_cost) }}</td>
      </tr>
      {% if base_scopes and optional_scopes %}
      <tr>
        <td colspan="3" style="padding: 4px 8px; text-align: right; font-size: 8pt; background-color: #2E5FA3; color: #ffffff;">Base Scope Grand Total Direct Cost</td>
        <td class="amount-cell" style="padding: 4px 8px; font-size: 8pt; background-color: #2E5FA3; color: #ffffff;">{{ php_format(doc.base_direct_cost) }}</td>
      </tr>
      {% endif %}

    </tbody>
  </table>

  {# BP Waterfall — full-width, gold accent #}
  <div style="margin-top: 6mm;">
    {{ render_waterfall_block(bp_all_dc, bp_ocm_pct, bp_profit_pct, doc.vat_inclusive, doc.vat_percent | float, "#C89A2E") }}
  </div>

  {# Amount in words — formal Philippine construction proposal convention #}
  <div style="margin-top: 5mm; padding: 4px 8px; font-size: 8.5pt; font-style: italic; color: #2D3142; border-top: 1px solid #e0e0e0;">
    <strong>Amount in Words:</strong> {{ amount_in_words(doc.bp_grand_total) }}
  </div>

  <div style="margin-top: 3mm; font-size: 7.5pt; color: #666666; text-align: right; font-style: italic;">
    BP Contract Amount (rate factor: {{ num_format(bp_rate) }}x, OCM: {{ num_format(bp_ocm_pct) }}%, Profit: {{ num_format(bp_profit_pct) }}%)
  </div>

  {% if optional_scopes %}
  <div style="margin-top: 4mm; font-size: 8pt; font-style: italic; color: #666666; text-align: right;">
    * BP Contract Amount includes optional scopes ({{ optional_scopes | length }} scope{{ 's' if optional_scopes | length != 1 }}).
  </div>
  {% endif %}

  {% else %}
  <div style="padding: 20mm 0; text-align: center; color: #888888; font-style: italic;">
    <p style="font-size: 11pt;">No scopes added</p>
    <p style="margin-top: 4mm; font-size: 9pt;">BP Contract Amount: {{ php_format(0) }}</p>
  </div>
  {% endif %}

</div>{# end summary page #}

{# =========================================================================
   SCOPE DETAIL PAGES — BP VARIANT
   Sections A/B/C, Equipment LEFT JOIN, full-width waterfall
========================================================================= #}

{% set scopes_detail = frappe.db.sql("""
    SELECT name, scope_name, scope_group, is_optional, dpwh_pay_item,
           uom, quantity, output_per_day, duration_days, display_order,
           direct_cost, total_labor_cost, total_equipment_cost, total_material_cost
    FROM `tabEstimate Scope`
    WHERE estimate = %s
    ORDER BY scope_group ASC, COALESCE(display_order, 999) ASC, name ASC
""", doc.name, as_dict=True) %}

{% set scope_count = scopes_detail | length %}
{% set current_group = namespace(value=None) %}

{% if scope_count > 0 %}

{% if doc.cost_display_mode == "Summary (Private)" %}
{# Summary (Private) mode — BP variant #}
{% for scope in scopes_detail %}

  {# Compute BP direct cost for this scope #}
  {% set scope_mat_rows = frappe.db.sql("SELECT amount FROM `tabEstimate Scope Material` WHERE parent = %s", scope.name, as_dict=True) %}
  {% set scope_bp_mat = namespace(value=0) %}
  {% for row in scope_mat_rows %}{% set scope_bp_mat.value = scope_bp_mat.value + (row.amount | float) * bp_rate %}{% endfor %}
  {% set scope_bp_dc = (scope.total_labor_cost | float) + (scope.total_equipment_cost | float) + scope_bp_mat.value %}

  <div style="page-break-before: always;">

    {{ cont_header() }}

    <table style="width: 100%; background-color: #1B2E4A; color: #ffffff; margin-bottom: 4mm; border-collapse: collapse;">
      <tr>
        <td style="padding: 5px 8px; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 9pt; color: #ffffff; vertical-align: top;">
          <strong>SCOPE {{ wbs[scope.name].scope_num }}</strong>: {{ scope.scope_name }}
          {% if scope.is_optional %}<span style="font-style: italic; color: #CCCCCC;"> (Optional)</span>{% endif %}
        </td>
        <td style="padding: 5px 8px; text-align: right; font-size: 8.5pt; color: #ffffff; vertical-align: top; white-space: nowrap;">
          {{ scope.uom if scope.uom and scope.uom != "None" else "" }} &times; {{ num_format(scope.quantity) }}
        </td>
      </tr>
      <tr>
        <td colspan="2" style="padding: 0 10px 6px 10px; font-size: 8pt; color: #D0D7E0;">
          {{ wbs._group_numerals[scope.scope_group] }}. {{ scope.scope_group }}
          {% if scope.dpwh_pay_item %} | Pay Item: {{ scope.dpwh_pay_item }}{% endif %}
        </td>
      </tr>
    </table>

    <div style="margin-bottom: 4mm;">
      <table style="width: 100%; border-collapse: collapse; font-size: 9pt;">
        <thead>
          <tr>
            <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: left;">Description</th>
            <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: right;">BP Unit Cost</th>
            <th style="background-color: #3B5998; color: #ffffff; padding: 4px 6px; text-align: right;">BP Direct Cost</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ scope.scope_name }}</td>
            {% set bp_unit_cost = scope_bp_dc / (scope.quantity | float) if (scope.quantity | float) > 0 else 0 %}
            <td class="amount-cell" style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ php_format(bp_unit_cost) }}</td>
            <td class="amount-cell" style="padding: 3px 6px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope_bp_dc) }}</td>
          </tr>
        </tbody>
      </table>
    </div>

    <div style="margin-top: 8mm; page-break-inside: avoid;">
      {{ render_waterfall_block(scope_bp_dc, bp_ocm_pct, bp_profit_pct, doc.vat_inclusive, doc.vat_percent | float, "#C89A2E", scope.scope_name) }}
    </div>

  </div>
{% endfor %}

{% else %}
{# Detailed (DPWH) mode — BP variant #}
{% for scope in scopes_detail %}

  {# Compute BP direct cost for this scope #}
  {% set scope_mat_rows_bp = frappe.db.sql("SELECT amount FROM `tabEstimate Scope Material` WHERE parent = %s", scope.name, as_dict=True) %}
  {% set scope_bp_mat_cost = namespace(value=0) %}
  {% for row in scope_mat_rows_bp %}{% set scope_bp_mat_cost.value = scope_bp_mat_cost.value + (row.amount | float) * bp_rate %}{% endfor %}
  {% set scope_bp_dc = (scope.total_labor_cost | float) + (scope.total_equipment_cost | float) + scope_bp_mat_cost.value %}

  <div style="page-break-before: always;">

    {{ cont_header() }}

    {% if scope.scope_group != current_group.value %}
      {% set current_group.value = scope.scope_group %}
      <div style="background-color: #1B2E4A; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 4px 8px; letter-spacing: 1px; font-size: 9.5pt; margin-bottom: 4mm;">
        {{ wbs._group_numerals[scope.scope_group] }}. {{ scope.scope_group | upper }}
      </div>
    {% endif %}

    <table style="width: 100%; background-color: #1B2E4A; color: #ffffff; margin-bottom: 4mm; border-collapse: collapse;">
      <tr>
        <td style="padding: 5px 8px; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 9pt; color: #ffffff; vertical-align: top;">
          <strong>SCOPE {{ wbs[scope.name].scope_num }}</strong>: {{ scope.scope_name }}
          {% if scope.is_optional %}<span style="font-style: italic; color: #CCCCCC;"> (Optional)</span>{% endif %}
          {% if scope.dpwh_pay_item %}
          <div style="font-size: 8pt; color: #D0D7E0; margin-top: 2px;">Pay Item: {{ scope.dpwh_pay_item }}</div>
          {% endif %}
        </td>
        <td style="padding: 5px 8px; text-align: right; font-size: 8.5pt; color: #ffffff; vertical-align: top; white-space: nowrap;">
          {{ wbs._group_numerals[scope.scope_group] }}. {{ scope.scope_group }}
        </td>
      </tr>
      <tr>
        <td colspan="2" style="padding: 0 10px 6px 10px; font-size: 8pt; color: #E0E4E8;">
          {% set uom_display = scope.uom if scope.uom and scope.uom != "None" else "" %}
          {% if uom_display %}UOM: {{ uom_display }} &nbsp;|&nbsp; {% endif %}Qty: {{ num_format(scope.quantity) }}
          &nbsp;|&nbsp; Output/Day: {{ num_format(scope.output_per_day) }}
          &nbsp;|&nbsp; Duration: {{ num_format(scope.duration_days) }} days
        </td>
      </tr>
    </table>

    {% set labor_rows = frappe.db.sql("SELECT role, persons, daily_rate, total_rate, total_cost FROM `tabEstimate Scope Labor` WHERE parent = %s ORDER BY idx", scope.name, as_dict=True) %}
    {% if labor_rows %}
    <div class="section-header">A &mdash; LABOR</div>
    {{ render_labor_table(labor_rows, scope.duration_days | float) }}
    {% endif %}

    {% set equipment_rows = frappe.db.sql("SELECT e.item AS item_code, COALESCE(i.item_name, e.item) AS item_name, e.units, e.daily_rate, e.total_rate, e.total_cost FROM `tabEstimate Scope Equipment` e LEFT JOIN `tabItem` i ON i.name = e.item WHERE e.parent = %s ORDER BY e.idx", scope.name, as_dict=True) %}
    {% if equipment_rows %}
    <div class="section-header">B &mdash; EQUIPMENT &amp; PLANT</div>
    {{ render_equipment_table(equipment_rows, scope.duration_days | float) }}
    {% endif %}

    {% set material_rows = frappe.db.sql("SELECT m.item AS item_code, m.item_name, m.adjusted_qty, m.uom, m.buying_rate, m.amount, i.description AS item_description FROM `tabEstimate Scope Material` m LEFT JOIN `tabItem` i ON m.item = i.name WHERE m.parent = %s ORDER BY m.idx", scope.name, as_dict=True) %}
    {% if material_rows %}
    <div class="section-header">C &mdash; MATERIALS</div>
    {{ render_material_table(material_rows, wbs[scope.name].scope_num) }}
    {% if bp_rate != 1.0 %}
    <div style="font-size: 7.5pt; color: #777777; font-style: italic; text-align: right; margin-top: 2mm; margin-right: 4mm;">
      * Material amounts adjusted by BP factor {{ num_format(bp_rate) }}x in waterfall below.
    </div>
    {% endif %}
    {% endif %}

    <div style="margin-top: 8mm; page-break-inside: avoid;">
      {{ render_waterfall_block(scope_bp_dc, bp_ocm_pct, bp_profit_pct, doc.vat_inclusive, doc.vat_percent | float, "#C89A2E", scope.scope_name) }}
    </div>

  </div>
{% endfor %}
{% endif %}

{% endif %}{# end scope_count > 0 #}

