      <tr>
        <td style="width: 50%; text-align: center; padding: 0 8mm; vertical-align: top;">
          <div style="font-size: 7.5pt; font-weight: bold; color: #1B2E4A; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 12mm;">For the Contractor</div>
          <div style="border-bottom: 1px solid #1B2E4A; margin: 0 4mm 2mm 4mm;">&nbsp;</div>
          <div style="font-size: 8.5pt; color: #2D3142; font-weight: bold;">SolidWurth Corp.</div>
