  }
  {% endif %}
  {% if fonts.roboto_mono %}
  @font-face {
    font-family: 'Roboto Mono';
    font-weight: 400;
    font-style: normal;
    src: url('data:font/woff2;base64,{{ fonts.roboto_mono }}') format('woff2');
  }
  {% endif %}

  /* -----------------------------------------------------------------------
     Table Defaults — wkhtmltopdf-safe (NO flexbox anywhere)
  ----------------------------------------------------------------------- */
  table {
    width: 100%;
    border-collapse: collapse;
  }

  thead {
    display: table-header-group;
  }

  tbody tr {
    page-break-inside: avoid;
  }

  .summary-table {
    table-layout: fixed;
  }

  .waterfall-table {
    page-break-inside: avoid;
  }

  /* -----------------------------------------------------------------------
     Cover Page Info Table
  ----------------------------------------------------------------------- */
  .info-label {
    padding: 3px 6px;
    font-weight: bold;
    color: #1B2E4A;
    width: 35%;
    white-space: nowrap;
    font-size: 10pt;
    border-bottom: 1px solid #e0e0e0;
    vertical-align: top;
  }

  .info-value {
    padding: 3px 6px;
    color: #2D3142;
    font-size: 10pt;
    border-bottom: 1px solid #e0e0e0;
    vertical-align: top;
  }

  /* -----------------------------------------------------------------------
     Section Headers (DLIA sections A/B/C)
  ----------------------------------------------------------------------- */
  .section-header {
    background-color: #2E5FA3;
    color: #ffffff;
    padding: 2px 8px;
    font-size: 8pt;
    font-weight: bold;
    margin-bottom: 1mm;
    margin-top: 3mm;
  }

  /* -----------------------------------------------------------------------
     Terms & Conditions Content Styling
     Styles semantic HTML from Frappe's Text Editor (Quill WYSIWYG)
     to match professional construction proposal formatting.
  ----------------------------------------------------------------------- */
  .terms-content ol {
    counter-reset: terms-counter;
    list-style: none;
    padding-left: 0;
    margin: 0;
  }

  .terms-content ol > li {
    counter-increment: terms-counter;
    padding: 3px 0 3px 24px;
    position: relative;
    margin-bottom: 4px;
    border-bottom: 1px solid #f0f0f0;
  }

  .terms-content ol > li::before {
    content: counter(terms-counter) ".";
    position: absolute;
    left: 0;
    font-weight: 700;
    color: #1B2E4A;
    min-width: 20px;
  }

  .terms-content ul {
    padding-left: 20px;
    margin: 2px 0;
  }

  .terms-content ul > li {
    padding: 1px 0;
    list-style-type: disc;
  }

  .terms-content h4, .terms-content h3 {
    font-size: 9pt;
    font-weight: 700;
    color: #1B2E4A;
    margin: 6px 0 3px 0;
    font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif;
  }

  .terms-content p {
    margin: 2px 0;
  }

  .terms-content strong {
    font-weight: 700;
    color: #1B2E4A;
  }

  .terms-content table {
    border-collapse: collapse;
    margin: 4px 0;
  }

  .terms-content table td,
  .terms-content table th {
    padding: 2px 6px;
    border: 1px solid #e0e0e0;
    font-size: 8.5pt;
  }

</style>

