    {% endif %}
    <div style="font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-weight: 700; font-size: 30pt; color: #ffffff; letter-spacing: 2px; text-transform: uppercase;">COST PROPOSAL</div>
    <div style="width: 80mm; height: 4px; background-color: #A52422; margin: 8mm auto 0 auto;"></div>
  </div>

  {# Project info table #}
  <div style="padding: 12mm 20mm;">
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 8mm;">
      <tbody>
